(function() {
  'use strict';

  if (window.__ghDirDownloadActive) return;
  window.__ghDirDownloadActive = true;

  const BUTTON_ID = 'ba-gh-dir-download';
  const JSZIP_CDN = 'https://cdnjs.cloudflare.com/ajax/libs/jszip/3.10.1/jszip.min.js';

  function parseRepoPath() {
    const match = location.pathname.match(/^\/([^/]+)\/([^/]+)\/tree\/([^/]+)\/(.+)/);
    if (!match) return null;
    return { owner: match[1], repo: match[2], branch: match[3], path: match[4] };
  }

  function loadJSZip() {
    return new Promise(function(resolve, reject) {
      if (window.JSZip) { resolve(window.JSZip); return; }
      var s = document.createElement('script');
      s.src = JSZIP_CDN;
      s.onload = function() { resolve(window.JSZip); };
      s.onerror = function() { reject(new Error('Failed to load JSZip')); };
      document.head.appendChild(s);
    });
  }

  async function fetchTree(owner, repo, branch, path) {
    var apiUrl = 'https://api.github.com/repos/' + owner + '/' + repo + '/git/trees/' + branch + '?recursive=1';
    var resp = await fetch(apiUrl);
    if (!resp.ok) throw new Error('GitHub API error: ' + resp.status);
    var data = await resp.json();
    return data.tree.filter(function(item) {
      return item.path.startsWith(path + '/') || item.path === path;
    });
  }

  async function fetchBlob(url) {
    var resp = await fetch(url);
    if (!resp.ok) throw new Error('Failed to fetch: ' + url);
    var data = await resp.json();
    return Uint8Array.from(atob(data.content), function(c) { return c.charCodeAt(0); });
  }

  async function downloadDirectory(info, button) {
    try {
      button.textContent = 'Loading JSZip...';
      button.disabled = true;
      var JSZip = await loadJSZip();

      button.textContent = 'Fetching file tree...';
      var tree = await fetchTree(info.owner, info.repo, info.branch, info.path);
      var blobs = tree.filter(function(item) { return item.type === 'blob'; });

      if (blobs.length === 0) {
        button.textContent = 'No files found';
        setTimeout(function() { button.textContent = 'Download Directory'; button.disabled = false; }, 2000);
        return;
      }

      var zip = new JSZip();
      var dirName = info.path.split('/').pop() || info.repo;

      for (var i = 0; i < blobs.length; i++) {
        button.textContent = 'Downloading ' + (i + 1) + '/' + blobs.length + '...';
        var relativePath = blobs[i].path.substring(info.path.length + 1);
        var content = await fetchBlob(blobs[i].url);
        zip.file(relativePath, content);
      }

      button.textContent = 'Creating ZIP...';
      var blob = await zip.generateAsync({ type: 'blob' });
      var a = document.createElement('a');
      a.href = URL.createObjectURL(blob);
      a.download = dirName + '.zip';
      a.click();
      URL.revokeObjectURL(a.href);

      button.textContent = 'Downloaded!';
      setTimeout(function() { button.textContent = 'Download Directory'; button.disabled = false; }, 2000);
    } catch (err) {
      console.error('[GH Dir Download]', err);
      button.textContent = 'Error: ' + err.message;
      setTimeout(function() { button.textContent = 'Download Directory'; button.disabled = false; }, 3000);
    }
  }

  function injectButton() {
    if (document.getElementById(BUTTON_ID)) return;
    var info = parseRepoPath();
    if (!info) return;

    var target = document.querySelector('[class*="Box-sc"] [class*="TreeView"]') ||
                 document.querySelector('div[aria-labelledby*="folders-and-files"]') ||
                 document.querySelector('.Box .Details');
    if (!target) return;

    var wrapper = target.closest('[class*="Box-sc"]') || target.parentElement;
    if (!wrapper) return;

    var btn = document.createElement('button');
    btn.id = BUTTON_ID;
    btn.textContent = 'Download Directory';
    btn.style.cssText = 'margin:8px 16px;padding:5px 16px;font-size:14px;font-weight:500;line-height:20px;cursor:pointer;border:1px solid rgba(27,31,36,0.15);border-radius:6px;color:#fff;background-color:#2ea44f;font-family:-apple-system,BlinkMacSystemFont,"Segoe UI",Helvetica,Arial,sans-serif;';
    btn.addEventListener('mouseenter', function() { btn.style.backgroundColor = '#2c974b'; });
    btn.addEventListener('mouseleave', function() { btn.style.backgroundColor = '#2ea44f'; });
    btn.addEventListener('click', function() { downloadDirectory(info, btn); });

    wrapper.insertBefore(btn, wrapper.firstChild);
  }

  injectButton();

  var observer = new MutationObserver(function() {
    if (!document.getElementById(BUTTON_ID)) injectButton();
  });
  observer.observe(document.body, { childList: true, subtree: true });

  console.log('[GitHub Directory Download] Active — look for the download button on directory pages.');
})();
